**Idea — recursive DFS**: Depth of an empty tree is 0; otherwise it's `1 + max(depthLeft, depthRight)`.

```javascript
class TreeNode { constructor(val, left, right) { this.val = val ?? 0; this.left = left ?? null; this.right = right ?? null; } }
function arrayToTree(arr) {
  if (!arr || arr.length === 0 || arr[0] === null) return null;
  const root = new TreeNode(arr[0]); const q = [root]; let i = 1;
  while (q.length && i < arr.length) {
    const node = q.shift();
    if (i < arr.length && arr[i] !== null) { node.left = new TreeNode(arr[i]); q.push(node.left); } i++;
    if (i < arr.length && arr[i] !== null) { node.right = new TreeNode(arr[i]); q.push(node.right); } i++;
  }
  return root;
}
function treeToArray(root) {
  if (!root) return [];
  const out = []; const q = [root];
  while (q.length) {
    const n = q.shift();
    if (n === null) { out.push(null); continue; }
    out.push(n.val);
    q.push(n.left); q.push(n.right);
  }
  while (out.length && out[out.length-1] === null) out.pop();
