**Idea — preorder with null markers**: Serialize via preorder DFS emitting node values and '#' for nulls. Deserialize by consuming tokens left-to-right, with each '#' producing null and each value spawning a node whose children are the next two recursive deserializations.

```javascript
class TreeNode { constructor(val, left, right) { this.val = val ?? 0; this.left = left ?? null; this.right = right ?? null; } }
function arrayToTree(arr) {
  if (!arr || arr.length === 0 || arr[0] === null) return null;
  const root = new TreeNode(arr[0]); const q = [root]; let i = 1;
  while (q.length && i < arr.length) {
    const node = q.shift();
    if (i < arr.length && arr[i] !== null) { node.left = new TreeNode(arr[i]); q.push(node.left); } i++;
    if (i < arr.length && arr[i] !== null) { node.right = new TreeNode(arr[i]); q.push(node.right); } i++;
  }
  return root;
}
function treeToArray(root) {
  if (!root) return [];
  const out = []; const q = [root];
  while (q.length) {
    const n = q.shift();
    if (n === null) { out.push(null); continue; }
    out.push(n.val);
    q.push(n.left); q.push(n.right);
  }
  while (out.length && out[out.length-1] === null) out.pop();
  return out;
}
function preorderRoundTrip(data) {
  const tree = arrayToTree(data);
  const parts = [];
  const ser = (n) => {
    if (!n) { parts.push('#'); return; }
    parts.push(String(n.val));
    ser(n.left); ser(n.right);
  };
  ser(tree);
  const s = parts.join(',');
  const tokens = s.split(',');
  let idx = 0;
  const de = () => {
    if (idx >= tokens.length) return null;
    const t = tokens[idx++];
    if (t === '#') return null;
    const node = new TreeNode(parseInt(t, 10));
    node.left = de();
    node.right = de();
    return node;
  };
  const restored = de();
  return treeToArray(restored);
}
function solve(data) { return preorderRoundTrip(data); }
```

**Time**: O(n). **Space**: O(n).

