editorial:
**Idea — DFS returning best root-to-leaf chain**: At a node with both children, the best leaf-to-leaf path through it is `leftChain + rightChain + node.val`. Track the global best while propagating only the better chain upward.

```javascript
class TreeNode { constructor(val, left, right) { this.val = val ?? 0; this.left = left ?? null; this.right = right ?? null; } }
function arrayToTree(arr) {
  if (!arr || arr.length === 0 || arr[0] === null) return null;
  const root = new TreeNode(arr[0]); const q = [root]; let i = 1;
  while (q.length && i < arr.length) {
    const node = q.shift();
    if (i < arr.length && arr[i] !== null) { node.left = new TreeNode(arr[i]); q.push(node.left); } i++;
    if (i < arr.length && arr[i] !== null) { node.right = new TreeNode(arr[i]); q.push(node.right); } i++;
  }
  return root;
}
function treeToArray(root) {
  if (!root) return [];
  const out = []; const q = [root];
  while (q.length) {
    const n = q.shift();
    if (n === null) { out.push(null); continue; }
    out.push(n.val);
    q.push(n.left); q.push(n.right);
  }
  while (out.length && out[out.length-1] === null) out.pop();
  return out;
}
function maxLeafToLeaf(root) {
  let best = -Infinity;
  const dfs = (n) => {
    if (!n) return -Infinity;
    if (!n.left && !n.right) return n.val;
    const l = dfs(n.left);
    const r = dfs(n.right);
    if (n.left && n.right) {
      const cand = l + r + n.val;
      if (cand > best) best = cand;
      return Math.max(l, r) + n.val;
    }
    return (n.left ? l : r) + n.val;
  };
  dfs(root);
  return best === -Infinity ? -10000 : best;
}
function solve(arr) { return maxLeafToLeaf(arrayToTree(arr)); }
```

**Time**: O(n). **Space**: O(h).
